import React, { useState, useEffect, createContext, useContext, useMemo } from 'react';
import { View, ActivityIndicator, Text, TextInput, Button, StyleSheet, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

// --- 1. AuthContext: Manages global authentication state ---

const AuthContext = createContext();

const AUTH_TOKEN_KEY = 'userToken';
const USER_DATA_KEY = 'userData';

function AuthProvider({ children }) {
  const [isLoading, setIsLoading] = useState(true);
  const [userToken, setUserToken] = useState(null);
  const [userData, setUserData] = useState(null);

  useEffect(() => {
    // Restore token from AsyncStorage on app start
    const restoreToken = async () => {
      try {
        const storedToken = await AsyncStorage.getItem(AUTH_TOKEN_KEY);
        const storedUserData = await AsyncStorage.getItem(USER_DATA_KEY);

        if (storedToken && storedUserData) {
          setUserToken(storedToken);
          setUserData(JSON.parse(storedUserData));
        }
      } catch (e) {
        console.error('Failed to load token or user data from storage:', e);
      } finally {
        setIsLoading(false);
      }
    };

    restoreToken();
  }, []);

  const authContext = useMemo(
    () => ({
      signIn: async (email, password) => {
        setIsLoading(true);
        try {
          // --- Mock API call for sign-in ---
          // In a real app, you would make a network request here
          // e.g., const response = await api.post('/login', { email, password });
          // const { token, user } = response.data;
          
          // Simulate network delay
          await new Promise(resolve => setTimeout(resolve, 1500));

          if (email === 'test@example.com' && password === 'password123') {
            const token = 'mock-auth-token-123'; // Replace with actual token from API
            const user = { id: 'user-1', email: email, name: 'Test User' }; // Replace with actual user data from API

            await AsyncStorage.setItem(AUTH_TOKEN_KEY, token);
            await AsyncStorage.setItem(USER_DATA_KEY, JSON.stringify(user));

            setUserToken(token);
            setUserData(user);
            return { success: true };
          } else {
            throw new Error('Invalid credentials');
          }
        } catch (error) {
          Alert.alert('Login Failed', error.message || 'An unknown error occurred.');
          return { success: false, error: error.message };
        } finally {
          setIsLoading(false);
        }
      },
      signOut: async () => {
        setIsLoading(true);
        try {
          await AsyncStorage.removeItem(AUTH_TOKEN_KEY);
          await AsyncStorage.removeItem(USER_DATA_KEY);
          setUserToken(null);
          setUserData(null);
        } catch (e) {
          console.error('Failed to clear storage:', e);
        } finally {
          setIsLoading(false);
        }
      },
      userToken,
      userData,
      isLoading,
    }),
    [userToken, userData, isLoading]
  );

  return (
    <AuthContext.Provider value={authContext}>
      {children}
    </AuthContext.Provider>
  );
}

// --- 2. Screens ---

function LoadingScreen() {
  return (
    <View style={styles.container}>
      <ActivityIndicator size="large" color="#0000ff" />
      <Text style={styles.loadingText}>Loading...</Text>
    </View>
  );
}

function LoginScreen() {
  const [email, setEmail] = useState('test@example.com');
  const [password, setPassword] = useState('password123');
  const { signIn, isLoading } = useContext(AuthContext);

  const handleLogin = async () => {
    const result = await signIn(email, password);
    if (!result.success) {
      // Alert is already shown by signIn, but you could add more specific UI feedback here
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome Back!</Text>
      <TextInput
        style={styles.input}
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        keyboardType="email-address"
        autoCapitalize="none"
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
      />
      <Button title={isLoading ? "Logging in..." : "Login"} onPress={handleLogin} disabled={isLoading} />
    </View>
  );
}

function HomeScreen() {
  const { signOut, userData } = useContext(AuthContext);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Hello, {userData?.name || 'User'}!</Text>
      <Text style={styles.subtitle}>Your email: {userData?.email}</Text>
      <Text style={styles.subtitle}>You are successfully logged in.</Text>
      <Button title="Logout" onPress={signOut} color="#dc3545" />
    </View>
  );
}

// --- 3. Navigation Setup ---

const AuthStack = createNativeStackNavigator();
const AppStack = createNativeStackNavigator();

function AuthNavigator() {
  return (
    <AuthStack.Navigator screenOptions={{ headerShown: false }}>
      <AuthStack.Screen name="Login" component={LoginScreen} />
    </AuthStack.Navigator>
  );
}

function AppNavigator() {
  return (
    <AppStack.Navigator>
      <AppStack.Screen name="Home" component={HomeScreen} options={{ title: 'Dashboard' }} />
    </AppStack.Navigator>
  );
}

function RootNavigator() {
  const { userToken, isLoading } = useContext(AuthContext);

  if (isLoading) {
    return <LoadingScreen />;
  }

  return (
    <NavigationContainer>
      {userToken ? <AppNavigator /> : <AuthNavigator />}
    </NavigationContainer>
  );
}

// --- 4. Main App Component ---

export default function App() {
  return (
    <AuthProvider>
      <RootNavigator />
    </AuthProvider>
  );
}

